var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AURA_ADMIN_NULL_NULL","text":{"KOREA":"빠르고! 강하게!","JPN":"速く！　強く！","ENG":"Fast and strong!","TWN":"快又強！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AURA_ADMIN_NULL_NULL","text":{"KOREA":"적을 섬멸한다────!!","JPN":"敵を殲滅する────！！","ENG":"Annihilate the enemy────!!","TWN":"殲滅敵人────！！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>손상 부위─── 수리 불───가.</color>","JPN":"<color=#ff3636>損傷部位───修理不───可。</color>","ENG":"<color=#ff3636>Damage sustained─── repairs impos───sible.</color>","TWN":"<color=#ff3636>損壞部位───無法───維修。</color>"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>시스템─── 다운──.</color>","JPN":"<color=#ff3636>システム───ダウン。</color>","ENG":"<color=#ff3636>System─── down──.</color>","TWN":"<color=#ff3636>系統─── 停機──</color>"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AURA_ADMIN_NULL_NULL","text":{"KOREA":"이 몸! 약자를 수호하고 정의를 관철하는 방랑 기사!","JPN":"この私が弱者を守り、正義を貫く放浪の騎士！","ENG":"I am the wandering knight who shields the weak and upholds justice!","TWN":"本小姐！扶持弱者貫徹正義的流浪騎士！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AURA_ADMIN_NULL_NULL","text":{"KOREA":"오늘도, 정의 실현───!","JPN":"今日も、正義実現───！","ENG":"Once more, justice prevails───!","TWN":"今天也要實現正義───！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"우오오…! 혼자서 대 침식 4종 섬멸 병기를 쓰러트릴 줄이야……!","JPN":"うおお……！　一人で対侵食第4種殲滅兵器を倒すだなんて……！","ENG":"Whoa...! Took down an Anti-Corruption Category 4 Weapon all on your own...!","TWN":"哇喔…！竟然獨自打倒殲滅侵蝕4類兵器……！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"굉장한데? 과연 쌤이 선별한 <color=#ffd34c>특기전력</color>이라고 할만하다.","JPN":"すごいやん。さすが先生が選別した<color=#ffd34c>特記戦力</color>いうだけのことはあるな。","ENG":"Impressive. No wonder Teach picked you as a <color=#ffd34c>Special Operations Asset</color>.","TWN":"厲害喔？果然不愧是老師挑選的<color=#ffd34c>特殊戰力</color>。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"하지만 저 가면… 어쩌면…….","JPN":"でもあの仮面……もしかすると……","ENG":"But that mask... maybe...","TWN":"但那個面具……說不定……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はあ、はあ、はあ……！","ENG":"*Huff* *Huff* *Huff...!*","TWN":"哈啊，哈啊，哈啊……！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"마, 니 괘안나, 호흡이 좀 가쁜 것 같은데?","JPN":"あんた大丈夫か？　呼吸が乱れとるやないか。","ENG":"Hey, you all right? You look winded.","TWN":"喂，你還好嗎？感覺你呼吸有點急促。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"아, 괜찮아요. 오러화를 하고 난 뒤에는 살짝 지쳐서요.","JPN":"あ、大丈夫です。オーラ化した後は少し疲れてしまうので。","ENG":"Ah, I'm fine. Just a little exhausted after using Aurafication.","TWN":"嗯，沒關係。進行奧蘿化之後有點疲憊。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"아무래도 아직 수련이 부족한 탓이겠죠.","JPN":"まだ修行が足りないんでしょうね。","ENG":"I guess I still need more training.","TWN":"看來還是因為我的修煉不夠吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"음, 그 정도로 카운터 능력을 끌어올려준다 카면, 확실히 보통 물건은 아닌 것 같다.","JPN":"うーん、それほどカウンター能力を引き上げてくれるなんて、絶対普通の代物じゃない。","ENG":"Mm, if it can boost your Counter ability that much, it's definitely no ordinary mask.","TWN":"嗯，如果能將制裁者的能力提升到那種程度，確實不是普通的角色。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"로빈 양? 혹시 그 가면, 내 한 번 봐도 되겠나?","JPN":"ロビン、その仮面ちょっと見せてくれへん？","ENG":"Robin? Mind if I take a closer look at that mask?","TWN":"蘿蘋？那個面具，能借我看一下嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"네? 오러 선생님을요?","JPN":"え？　オーラ先生をですか？","ENG":"Huh? You mean Ms. Aura?","TWN":"嗯？是要看奧蘿師父嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"마, 내도 트레저 헌터다. 아티팩트 감정은 기본 중에 기본이지!","JPN":"ウチもトレジャーハンターや。アーティファクトの鑑定は基本中の基本！","ENG":"Hey, I'm a treasure hunter too. Appraising Artifacts is basic stuff!","TWN":"哈，我也是個尋寶獵人。鑒定人造神器是基本功夫！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"그건 상관없지만…….","JPN":"それは構いませんが……","ENG":"I mean, I guess that's fine, but...","TWN":"可以是可以……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"흐흐흐흐…….","JPN":"ふふふふ………","ENG":"He he he he...!","TWN":"呵呵呵呵……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"미, 미리네 씨?","JPN":"マ、マリさん？","ENG":"M-Ms. Mi Rinae?","TWN":"宓，宓璃奈？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"로빈 양, 내 짧은 인생에서 배운 게 있다 아이가.","JPN":"ロビン。ウチはさ、この短い人生の中で学んだことがあんねん。","ENG":"Robin, if there's one thing life's taught me...","TWN":"蘿蘋，我在短暫的人生中學到一些東西。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"인간이란 계략을 꾸미면 꾸밀수록, 예기치 못한 사태로 계략이 와르르 무너지는기다.","JPN":"人間は計略を弄すれば弄するほど、予期せぬ事態で計略がくずれさるんや。","ENG":"It's that the more schemes humans plot, the easier they crumble to unforeseen events.","TWN":"就是人類的計畫永遠趕不上變化。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그라믄 어쩌겠노? 인간을 뛰어넘는 존재가 되야쓰겠지?","JPN":"じゃあどないする？　人間を超える存在になるしかないやろ？","ENG":"So what's the answer? You've got to go beyond being human!","TWN":"那該怎麼辦呢？當然必須成為超越人類的存在囉？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"무슨 말을 하시는 거예요, 미리네 씨?","JPN":"何を言っているんですか、マリさん？","ENG":"What are you talking about, Ms. Mi Rinae?","TWN":"你在說什麼呢，宓璃奈？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"나는 인간을 그만두겠다, 로빈!! 나는 인간을 초월할 테다!!","JPN":"ウチは人間をやめるで、ロビン！！　ウチは人間を超越するッ！！","ENG":"I renounce my humanity, Robin!! I will transcend mankind!!","TWN":"我決定不當人類了！蘿蘋！！我要超越人類！！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"앗, 미리네 씨가… 오러 선생님을……?","JPN":"あっ、マリさんが……オーラ先生を……？","ENG":"W-wait, Ms. Mi Rinae...! You're putting on Ms. Aura...?","TWN":"宓璃奈……把奧蘿師父……？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"으갸아아아아아아아아아아아아악───!!","JPN":"うぎゃあああああああああああっ───！！","ENG":"UWAAAAAAAHHHH────!!","TWN":"呃啊啊啊啊啊啊啊啊啊啊啊啊啊───！！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"아앗, 죄송해요. 미리네 씨!","JPN":"あっ、ごめんなさい、マリさん！","ENG":"Ahh, I'm sorry! Ms. Mi Rinae!","TWN":"對，對不起，宓璃奈！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};